import { useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";


const FAQS = [
  { q: "How do I calculate what percent X is of Y?", a: "Divide X by Y, then multiply by 100. For example: 25 is what percent of 200? Answer: (25  x  200)  x  100 = 12.5%." },
  { q: "How do I find what X% of Y is?", a: "Multiply Y by (X/100). For example: What is 15% of 80? Answer: 80  x  0.15 = 12." },
  { q: "How do I calculate a percentage increase?", a: "Percentage increase = ((New Value - Old Value) / Old Value)  x  100. If a price goes from $50 to $60, the increase is ((60-)  x  100 = 20%." },
  { q: "What is the percentage difference between two numbers?", a: "Percentage difference = |A - B| / ((A + B) / 2)  x  100. This is used when comparing two values with no clear 'original' or 'reference' value." },
  { q: "What is the difference between percentage change and percentage difference?", a: "Percentage change has a defined starting point (from X to Y). Percentage difference compares two values symmetrically with no directional relationship - useful for comparing measurements, prices from different vendors, etc." },
  { q: "How do I reverse a percentage to find the original value?", a: "If you know the result after a percentage increase, divide by (1 + percent/100). Example: A price after a 20% increase is $120. Original price = $120  x  1.20 = $100." },
  { q: "How do I calculate a percentage decrease?", a: "Percentage decrease = ((Old Value - New Value) / Old Value)  x  100. If a stock drops from $80 to $60: ((80-)  x  100 = 25% decrease." },
  { q: "What does basis points mean in percentages?", a: "One basis point (bps) = 0.01%. A 25 basis point interest rate increase means rates go up by 0.25%. This unit is used in finance to express small percentage changes precisely." },
];

type Mode = "pct-of" | "what-pct" | "pct-change";

export default function PercentageCalculator() {
  const [mode, setMode] = useState<Mode>("pct-of");
  const [valA, setValA] = useState(15);
  const [valB, setValB] = useState(100);

  let result = 0;
  let label = "";
  if (mode === "pct-of") { result = (valA / 100) * valB; label = `${valA}% of ${valB}`; }
  else if (mode === "what-pct") { result = valB > 0 ? (valA / valB) * 100 : 0; label = `${valA} is what % of ${valB}`; }
  else { result = valB !== 0 ? ((valA - valB) / Math.abs(valB)) * 100 : 0; label = `% change from ${valB} to ${valA}`; }

  const MODES: { key: Mode; label: string; desc: string }[] = [
    { key: "pct-of", label: "X% of Y", desc: "What is X% of a number?" },
    { key: "what-pct", label: "X is what % of Y", desc: "What percent is X of Y?" },
    { key: "pct-change", label: "% change", desc: "Percentage increase or decrease" },
  ];

  const modeDescriptions: Record<Mode, { aLabel: string; bLabel: string }> = {
    "pct-of": { aLabel: "Percentage (%)", bLabel: "Of this number" },
    "what-pct": { aLabel: "Value X", bLabel: "Total value Y" },
    "pct-change": { aLabel: "New Value", bLabel: "Original Value" },
  };

  return (
    <>
      <SEOHead
        title="Free Percentage Calculator Online - Calculate Any Percentage Instantly | CalcHive"
        description="Free online percentage calculator. Calculate percentages, percentage changes and what percent one number is of another instantly. 100% free for everyone, no signup required."
        canonical="/percentage-calculator"
        keywords="free percentage calculator, percentage calculator online free, calculate percentage free, percent change calculator free, what percent is calculator free"
        category="Math Calculators"
        faqs={FAQS}
      />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8">
          <span className="text-xs font-semibold uppercase tracking-widest text-amber-600 dark:text-amber-400 bg-amber-50 dark:bg-amber-950/50 px-3 py-1 rounded-full mb-4 inline-block">Math</span>
          <h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Percentage Calculator Online</h1>
          <p className="text-muted-foreground leading-relaxed">Use this free percentage calculator to calculate percentage free, percentage change, and what percent one number is of another. This percentage calculator online free also works as a percent change calculator free and what percent is calculator free.</p>
        </div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="flex flex-wrap gap-2 mb-6">
            {MODES.map(m => (
              <button key={m.key} onClick={() => setMode(m.key)} className={`px-4 py-1.5 rounded-full text-sm font-semibold border transition-all ${mode === m.key ? "bg-primary text-primary-foreground border-primary" : "bg-muted text-muted-foreground border-border"}`}>{m.label}</button>
            ))}
          </div>
          <p className="text-xs text-muted-foreground mb-4">{MODES.find(m => m.key === mode)?.desc}</p>
          <div className="grid grid-cols-2 gap-4 mb-8">
            {[
              { id: "val-a", label: modeDescriptions[mode].aLabel, val: valA, setVal: setValA },
              { id: "val-b", label: modeDescriptions[mode].bLabel, val: valB, setVal: setValB },
            ].map(({ id, label, val, setVal }) => (
              <div key={id}>
                <label htmlFor={id} className="text-sm font-semibold text-foreground block mb-2">{label}</label>
                <input id={id} type="number" inputMode="decimal" value={val} onChange={e => setVal(Number(e.target.value))} className="w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all" />
              </div>
            ))}
          </div>
          <motion.div key={`${mode}-${valA}-${valB}`} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
            <div className="bg-gradient-to-br from-amber-500 to-amber-700 rounded-2xl p-6 text-center shadow-lg">
              <p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">{label}</p>
              <p className="text-6xl font-black text-white tracking-tight" data-testid="result">
                {mode === "what-pct" || mode === "pct-change" ? `${result.toFixed(2)}%` : result.toFixed(4).replace(/\.?0+$/, "")}
              </p>
            </div>
          </motion.div>
        </section>
        <ShareButton />

        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Calculate Any Percentage for Free</h2>
          <p className="text-muted-foreground leading-relaxed">Percentages express a fraction as a portion of 100. Understanding which formula to use depends on what you know and what you're solving for. Here are the three most common percentage calculations:</p>
          <div className="bg-accent/60 border border-border rounded-2xl p-5 font-mono text-sm text-foreground space-y-2">
            <p>X% of Y = (X  x  100)  x  Y</p>
            <p>X is what % of Y = (X  x  Y)  x  100</p>
            <p>% change from A to B = ((B - A)  x  |A|)  x  100</p>
            <p className="text-xs text-muted-foreground mt-2">Positive % change = increase - Negative % change = decrease</p>
          </div>

          <h2 className="text-2xl font-bold text-foreground">How to Find Percentage Change Between Two Numbers</h2>
          <div className="overflow-x-auto">
            <table className="w-full text-sm border border-border rounded-xl overflow-hidden">
              <thead className="bg-muted/60">
                <tr>
                  {["Percentage", "Fraction", "Decimal", "Of $100", "Of $1,000"].map(h => <th key={h} className="text-left py-3 px-4 font-semibold text-foreground">{h}</th>)}
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {[
                  ["1%", "1/100", "0.01", "$1.00", "$10.00"],
                  ["5%", "1/20", "0.05", "$5.00", "$50.00"],
                  ["10%", "1/10", "0.10", "$10.00", "$100.00"],
                  ["15%", "3/20", "0.15", "$15.00", "$150.00"],
                  ["20%", "1/5", "0.20", "$20.00", "$200.00"],
                  ["25%", "1/4", "0.25", "$25.00", "$250.00"],
                  ["33.33%", "1/3", "0.333...", "$33.33", "$333.33"],
                  ["50%", "1/2", "0.50", "$50.00", "$500.00"],
                  ["75%", "3/4", "0.75", "$75.00", "$750.00"],
                  ["100%", "1/1", "1.00", "$100.00", "$1,000.00"],
                ].map(([pct, frac, dec, of100, of1000]) => (
                  <tr key={pct} className="hover:bg-muted/30">
                    <td className="py-2.5 px-4 font-semibold text-foreground">{pct}</td>
                    <td className="py-2.5 px-4 text-amber-600 dark:text-amber-400 font-medium">{frac}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{dec}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{of100}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{of1000}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </section>

        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">Free Percent Calculator for Students and Everyday Use</h2>
          <p className="text-muted-foreground leading-relaxed">Use this free tool on any device to solve the calculation instantly, check your work, and get a clear result without downloads or signup.</p>
        </section>

        <section className="mb-8">
          <h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3>
          <div className="space-y-3">{FAQS.map(f => <FAQItem key={f.q} q={f.q} a={f.a} />)}</div>
        </section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/percentage-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


